def main():
    doc = Document(str(INPUT))
    applied = []
    for idx, text in REWRITE_BY_INDEX.items():
        if idx < len(doc.paragraphs):
            doc.paragraphs[idx].text = text
            applied.append(idx)

    doc.save(str(OUTPUT))
    doc.save(str(OUTPUT_EN))
    print(f"saved: {OUTPUT}")
    print(f"saved: {OUTPUT_EN}")
    print(f"rewritten paragraphs: {len(applied)}")
    print(",".join(str(i) for i in applied))


if __name__ == "__main__":
    main()
